void VPScalarIVStepsRecipe::execute(VPTransformState &State) {
  // ... (existing code)
  Value *StartIdx0 = getOperand(0)->getLiveInIRValue(State);
  Value *Step = getOperand(1)->getLiveInIRValue(State);
  // ... (existing code)
  Type *IntStepTy = Step->getType();
  if (isa<VectorType>(IntStepTy))
    IntStepTy = cast<VectorType>(IntStepTy)->getElementType();

  // The start index may have a wider type than the step value. Truncate it to
  // the same type.
  StartIdx0 = Builder.CreateTrunc(StartIdx0, IntStepTy);

  // ... (rest of the function)
}
```

